fn isDigit(ch: u8) bool {
    return ch >= "0" and ch <= "9";
}

fn isAlnum(ch: u8) bool {
    return isDigit(ch) or (ch >= "a" and ch <= "z") or (ch >= "A" and ch <= "Z");
}

fn isEmailChar(ch: u8) bool {
    return isAlnum(ch) or ch == '.' or ch == '+' or ch == '-' or ch == '_';
}

